using System.Reflection;

var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.agents.ai/1.4.0/lib/net10.0/Microsoft.Agents.AI.dll");

void DumpType(string name)
{
    var t = asm.GetExportedTypes().FirstOrDefault(t => t.Name == name || t.FullName == name);
    if (t == null) { Console.WriteLine($"NOT FOUND: {name}"); return; }
    Console.WriteLine($"\n=== {t.FullName} (base: {t.BaseType?.Name}) ===");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.FlattenHierarchy))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
    foreach (var c in t.GetConstructors())
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        if (!m.IsSpecialName)
            Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}

DumpType("ChatClientAgentOptions");
DumpType("ChatClientAgentRunOptions");
DumpType("AgentSession");
DumpType("ChatClientAgentSession");
DumpType("AIAgent");

// Also check extension methods
var extTypes = new[] { "AIAgentExtensions", "ChatClientExtensions", "ChatClientBuilderExtensions" };
foreach (var name in extTypes)
{
    var t = asm.GetExportedTypes().FirstOrDefault(t => t.Name == name);
    if (t == null) continue;
    Console.WriteLine($"\n=== {t.FullName} (static) ===");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Static))
        Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}
