    if (t == null) { Console.WriteLine($"NOT FOUND: {name}"); return; }
    Console.WriteLine($"\n=== {t.FullName} (base: {t.BaseType?.Name}, abstract={t.IsAbstract}) ===");
    foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance))
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}" + (p.HasDefaultValue ? $" = {p.DefaultValue}" : "")))}) [{(c.IsPublic?"public":"protected")}]");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  prop {p.PropertyType.Name} {p.Name}");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        if (!m.IsSpecialName)
            Console.WriteLine($"  {m.ReturnType.Name} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}" + (p.HasDefaultValue ? $" = {p.DefaultValue}" : "")))})");
}

DumpAll("AgentSession");
DumpAll("AgentSessionStateBag");

// Check RunAsync return type more carefully
var agentType = asm.GetExportedTypes().First(t => t.Name == "ChatClientAgent");
foreach (var m in agentType.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
{
    if (!m.IsSpecialName)
    {
        var returnType = m.ReturnType;
        string returnStr = returnType.IsGenericType 
            ? $"{returnType.Name}<{string.Join(", ", returnType.GetGenericArguments().Select(a => a.FullName ?? a.Name))}>"
            : returnType.FullName ?? returnType.Name;
        Console.WriteLine($"  {returnStr} {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}" + (p.HasDefaultValue ? $" = {p.DefaultValue}" : "")))})");
    }
}
