using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability by querying DuckDuckGo and extracting results.
/// </summary>
public sealed partial class WebSearchTool
{
    private readonly HttpClient _httpClient;

    public WebSearchTool(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    [Description("Search the web for information on a given query. Returns a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";

            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var response = await _httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            return ParseSearchResults(html);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL. Use this to read full articles.")]
    public async Task<string> FetchPageAsync(
        [Description("The URL of the web page to fetch")] string url,
        CancellationToken cancellationToken = default)
    {
        try
        {
            using var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var response = await _httpClient.SendAsync(request, cancellationToken);
            response.EnsureSuccessStatusCode();

            var html = await response.Content.ReadAsStringAsync(cancellationToken);
            var text = ExtractTextFromHtml(html);

            const int maxLength = 4000;
            if (text.Length > maxLength)
                text = text[..maxLength] + "\n\n[Content truncated...]";

            return text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string ParseSearchResults(string html)
    {
        var results = new StringBuilder();
        var resultMatches = ResultPattern().Matches(html);
        var snippetMatches = SnippetPattern().Matches(html);

        int count = Math.Min(resultMatches.Count, 8);
        if (count == 0)
            return "No search results found.";

        for (int i = 0; i < count; i++)
        {
            var link = resultMatches[i];
            var href = WebUtility.HtmlDecode(link.Groups[1].Value);
            var title = StripHtml(WebUtility.HtmlDecode(link.Groups[2].Value));

            string snippet = i < snippetMatches.Count
                ? StripHtml(WebUtility.HtmlDecode(snippetMatches[i].Groups[1].Value))
                : "";

            results.AppendLine($"[{i + 1}] {title}");
            results.AppendLine($"    URL: {href}");
            if (!string.IsNullOrWhiteSpace(snippet))
                results.AppendLine($"    {snippet}");
            results.AppendLine();
        }

        return results.ToString();
    }

    private static string ExtractTextFromHtml(string html)
    {
        var text = ScriptStylePattern().Replace(html, " ");
        text = TagPattern().Replace(text, " ");
        text = WebUtility.HtmlDecode(text);
        text = WhitespacePattern().Replace(text, " ");
        text = MultiNewlinePattern().Replace(text.Trim(), "\n\n");
        return text;
    }

    private static string StripHtml(string html)
    {
        var text = TagPattern().Replace(html, "");
        return WhitespacePattern().Replace(text, " ").Trim();
    }

    [GeneratedRegex("""<a[^>]+class="result__a"[^>]+href="([^"]*)"[^>]*>(.*?)</a>""",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ResultPattern();

    [GeneratedRegex("""<a[^>]+class="result__snippet"[^>]*>(.*?)</a>""",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex SnippetPattern();

    [GeneratedRegex("""<(script|style)[^>]*>.*?</\1>""",
        RegexOptions.Singleline | RegexOptions.IgnoreCase)]
    private static partial Regex ScriptStylePattern();

    [GeneratedRegex("<[^>]+>")]
    private static partial Regex TagPattern();

    [GeneratedRegex(@"\s+")]
    private static partial Regex WhitespacePattern();

    [GeneratedRegex(@"\n{3,}")]
    private static partial Regex MultiNewlinePattern();
}

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// An in-memory note store that the research agent uses to collect findings.
/// </summary>
public sealed class NoteStore
{
    private readonly List<Note> _notes = [];

    [Description("Save a research note with a title and content. Use this to record important findings.")]
    public string TakeNote(
        [Description("A short title for the note")] string title,
        [Description("The content or finding to record")] string content)
    {
        var note = new Note(title, content, DateTime.UtcNow);
        _notes.Add(note);
        return $"Note saved: \"{title}\" (total notes: {_notes.Count})";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===\n");

        for (int i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine($"--- Note {i + 1}: {note.Title} ---");
            sb.AppendLine(note.Content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public IReadOnlyList<Note> Notes => _notes.AsReadOnly();

    public sealed record Note(string Title, string Content, DateTime CreatedAt);
}

